const kpiTranslation = {
  sessions: 'DAU / MAU',
  cpc: 'CPI（Cost Per Install）',
  bounceRate: 'Day1 Retention',
  avgSessionDuration: 'セッション時間・スクリーン数'
};

function calcStickiness(dau, mau) {
  return (dau / mau) * 100;
}

console.log('セッション数 →', kpiTranslation.sessions);
console.log('CPC →', kpiTranslation.cpc);
console.log('直帰率 →', kpiTranslation.bounceRate);
console.log('平均セッション時間 →', kpiTranslation.avgSessionDuration);

const dau = 50000;
const mau = 300000;
console.log('Stickiness:', calcStickiness(dau, mau).toFixed(1) + '%');
